const fetch = require('node-fetch');

const url = 'https://atmosphere.amentum.io/ipe/2d?latitude=21.0&longitude=-12.0&year=2024&month=3&day=25&hour=15&minute=10';

const options = {
  method: 'GET',
  headers: {
    'API-Key': '<your_key>',
    'accept': 'application/json'
  }
};

fetch(url, options)
  .then(response => response.json())
  .then(json_payload => console.log(JSON.stringify(json_payload, null, 4)))
  .catch(err => console.error('error:', err));

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;
import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

public class Main {
    public static void main(String[] args) {
        try {
            String url = "https://atmosphere.amentum.io/ipe/2d?latitude=21.0&longitude=-12.0&year=2024&month=3&day=25&hour=15&minute=10";

            HttpURLConnection conn = (HttpURLConnection) new URL(url).openConnection();
            conn.setRequestMethod("GET");
            conn.setRequestProperty("API-Key", "<your_key>");
            conn.setRequestProperty("accept", "application/json");

            BufferedReader in = new BufferedReader(new InputStreamReader(conn.getInputStream()));
            String inputLine;
            StringBuilder content = new StringBuilder();
            while ((inputLine = in.readLine()) != null) {
                content.append(inputLine);
            }

            in.close();
            conn.disconnect();

            Gson gson = new GsonBuilder().setPrettyPrinting().create();
            Object json_payload = gson.fromJson(content.toString(), Object.class);
            System.out.println(gson.toJson(json_payload));
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

#include <iostream>
#include <sstream>
#include <curl/curl.h>
#include <json/json.h>

size_t WriteCallback(void* contents, size_t size, size_t nmemb, void* userp)
{
    ((std::string*)userp)->append((char*)contents, size * nmemb);
    return size * nmemb;
}

int main() {
    CURL* curl;
    CURLcode res;
    std::string readBuffer;

    curl = curl_easy_init();
    if(curl) {
        curl_easy_setopt(curl, CURLOPT_URL, "https://atmosphere.amentum.io/ipe/2d?latitude=21.0&longitude=-12.0&year=2024&month=3&day=25&hour=15&minute=10");
        curl_easy_setopt(curl, CURLOPT_HTTPHEADER, curl_slist_append(NULL, "API-Key: <your_key>"));
        curl_easy_setopt(curl, CURLOPT_HTTPHEADER, curl_slist_append(NULL, "accept: application/json"));
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &readBuffer);
        res = curl_easy_perform(curl);
        curl_easy_cleanup(curl);

        Json::CharReaderBuilder builder;
        Json::CharReader* reader = builder.newCharReader();
        Json::Value json_payload;
        std::string errs;

        reader->parse(readBuffer.c_str(), readBuffer.c_str() + readBuffer.size(), &json_payload, &errs);
        delete reader;

        Json::StreamWriterBuilder writer;
        std::cout << Json::writeString(writer, json_payload) << std::endl;
    }
    return 0;
}

import Foundation

let url = URL(string: "https://atmosphere.amentum.io/ipe/2d?latitude=21.0&longitude=-12.0&year=2024&month=3&day=25&hour=15&minute=10")!
var request = URLRequest(url: url)
request.setValue("<your_key>", forHTTPHeaderField: "API-Key")
request.setValue("application/json", forHTTPHeaderField: "accept")

let task = URLSession.shared.dataTask(with: request) { data, response, error in
    guard let data = data, error == nil else {
        print("Error:", error ?? "Unknown error")
        return
    }

    if let json = try? JSONSerialization.jsonObject(with: data, options: .mutableContainers) {
        let jsonData = try! JSONSerialization.data(withJSONObject: json, options: .prettyPrinted)
        if let jsonString = String(data: jsonData, encoding: .utf8) {
            print(jsonString)
        }
    }
}

task.resume()

